import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY as string,
});

export async function POST(request: NextRequest) {
  const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

  const session = liveblocks.prepareSession(
    `user-${Math.random().toString(36).substring(2, 9)}`,
    {}
  );

  session.allow(roomId, session.FULL_ACCESS);

  const { body, status } = await session.authorize();

  return new NextResponse(body, { status });
}

"use client";

import { ClientSideSuspense } from "@liveblocks/react";
import { RoomProvider } from "@liveblocks/react";
import { LiveblocksProvider } from "@liveblocks/react";
import { ReactNode } from "react";

const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

export function LiveblocksRoom({ children }: { children: ReactNode }) {
  return (
    <LiveblocksProvider
      publicApiKey={process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY}
      authEndpoint="/api/liveblocks-auth"
    >
      <RoomProvider id={roomId} initialPresence={{ color: "#000000" }}>
        <ClientSideSuspense fallback={null}>
          {() => children}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import { useUpdateMyPresence, useOthers, useSelf } from "@liveblocks/react";
import { useCallback } from "react";

function ColorPicker() {
  const updateMyPresence = useUpdateMyPresence();
  const others = useOthers();
  const self = useSelf();

  const handleColorChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      updateMyPresence({ color: e.target.value });
    },
    [updateMyPresence]
  );

  const allUsers = [self, ...others.toArray()];

  return (
    <div>
      <input
        id="color-input"
        type="color"
        onChange={handleColorChange}
        defaultValue={self?.presence?.color ?? "#000000"}
      />
      <ul id="user-colors">
        {allUsers.map((user) => {
          if (!user) return null;
          const color = user.presence?.color ?? "#000000";
          return (
            <li
              key={user.connectionId}
              data-connection-id={user.connectionId}
              data-color={color}
              style={{ backgroundColor: color }}
            >
              User {user.connectionId}: {color}
            </li>
          );
        })}
      </ul>
    </div>
  );
}

export default function Page() {
  return <ColorPicker />;
}

